<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Maze Game</title>
    <style>
        body {
            font-family: sans-serif;
            text-align: center;
            margin-top: 20px;
        }
        #maze {
            border: 1px solid black;
            image-rendering: pixelated;
        }
        #hud {
            display: flex;
            justify-content: space-around;
            align-items: center;
            margin-top: 10px;
        }
        button {
            padding: 5px 10px;
            font-size: 16px;
        }
    </style>
</head>
<body>
    <canvas id="maze" width="400" height="400"></canvas>
    <div id="hud">
        <span id="completed">Completed: 0</span>
        <span id="timer">Time: 0ms</span>
        <button id="reset">Reset</button>
    </div>

    <script>
        const mazeEl = document.getElementById('maze');
        const mazeCtx = mazeEl.getContext('2d');

        class PriorityQueue {
            constructor() {
                this.elements = [];
            }
            enqueue(element, priority) {
                this.elements.push({ element, priority });
                this.elements.sort((a, b) => a.priority - b.priority);
            }
            dequeue() {
                return this.elements.shift().element;
            }
            isEmpty() {
                return this.elements.length === 0;
            }
        }

        function generateMaze(width, height) {
            const grid = new Array(height).fill(null).map(() =>
                new Array(width).fill(null).map(() => ({
                    walls: { top: true, right: true, bottom: true, left: true },
                    visited: false
                }))
            );

            function visit(x, y) {
                grid[y][x].visited = true;
                const directions = [
                    [0, -1], // up
                    [1, 0],  // right
                    [0, 1],  // down
                    [-1, 0]  // left
                ];
                let availableDirs = [];
                for (const [dx, dy] of directions) {
                    const nx = x + dx;
                    const ny = y + dy;
                    if (nx >= 0 && nx < width && ny >= 0 && ny < height && !grid[ny][nx].visited) {
                        availableDirs.push({ dx, dy });
                    }
                }

                if (availableDirs.length > 0) {
                    // Randomly choose a direction
                    const { dx, dy } = availableDirs[Math.floor(Math.random() * availableDirs.length)];
                    const nx = x + dx;
                    const ny = y + dy;

                    // Remove walls between current and new cell
                    if (dx === 1) grid[y][x].right = false; else if (dx === -1) grid[y][x].left = false;
                    if (dy === 1) grid[y][x].bottom = false; else if (dy === -1) grid[y][x].top = false;

                    if (dx === 1) grid[ny][nx].left = false; else if (dx === -1) grid[ny][nx].right = false;
                    if (dy === 1) grid[ny][nx].top = false; else if (dy === -1) grid[ny][nx].bottom = false;

                    visit(nx, ny);
                } else {
                    // Backtrack
                    return;
                }
            }

            const startX = 0;
            const startY = 0;
            visit(startX, startY);

            return grid;
        }

        function aStar(maze, start, end, botIndex) {
            const width = maze[0].length;
            const height = maze.length;
            const openSet = new PriorityQueue();
            const cameFrom = {};
            const gScore = {};
            const fScore = {};

            function heuristic(a, b) {
                return Math.abs(a.x - b.x) + Math.abs(a.y - b.y);
            }

            const startNode = { x: start[0], y: start[1] };
            openSet.enqueue(startNode, 0);
            gScore[startNode.x + ',' + startNode.y] = 0;
            fScore[startNode.x + ',' + startNode.y] = heuristic(startNode, end);

            while (!openSet.isEmpty()) {
                const current = openSet.dequeue();

                if (current.x === end.x && current.y === end.y) {
                    // Reconstruct path
                    const path = [];
                    let node = current;
                    while (node) {
                        path.push({ x: node.x, y: node.y });
                        node = cameFrom[node.x + ',' + node.y];
                    }
                    return path.reverse();
                }

                // Check all four directions
                const neighbors = [
                    { dx: 0, dy: -1 }, // up
                    { dx: 1, dy: 0 },  // right
                    { dx: 0, dy: 1 },  // down
                    { dx: -1, dy: 0 }  // left
                ].map(({ dx, dy }) => {
                    const nx = current.x + dx;
                    const ny = current.y + dy;
                    if (nx < 0 || nx >= width || ny < 0 || ny >= height) return null;

                    const cell = maze[ny][nx];
                    let hasWall = false;
                    // Check wall between current and neighbor
                    if (dx === 1 && maze[current.y][current.x].right) hasWall = true; // moving right, check current's right wall
                    else if (dx === -1 && maze[current.y][current.x].left) hasWall = true; // moving left, check current's left wall
                    else if (dy === 1 && maze[current.y][current.x].bottom) hasWall = true; // moving down, check current's bottom wall
                    else if (dy === -1 && maze[current.y][current.x].top) hasWall = true; // moving up, check current's top wall

                    return hasWall ? null : { x: nx, y: ny };
                }).filter(n => n !== null);

                for (const neighbor of neighbors) {
                    const keyCurrent = `${current.x},${current.y}`;
                    const tentativeGScore = (gScore[keyCurrent] || 0) + 1;
                    const keyNeighbor = `${neighbor.x},${neighbor.y}`;

                    if (tentativeGScore < (gScore[keyNeighbor] || Infinity)) {
                        cameFrom[keyNeighbor] = current;
                        gScore[keyNeighbor] = tentativeGScore;
                        fScore[keyNeighbor] = tentativeGScore + heuristic(neighbor, end);
                        // Add to open set with priority based on fScore and a tie-breaker
                        const priority = fScore[keyNeighbor] + (botIndex * 0.001); // small variation per bot
                        openSet.enqueue(neighbor, priority);
                    }
                }
            }

            return []; // no path found
        }

        function drawMaze() {
            mazeCtx.clearRect(0, 0, mazeEl.width, mazeEl.height);

            const cellWidth = mazeEl.width / mazeWidth;
            const cellHeight = mazeEl.height / mazeHeight;

            mazeCtx.strokeStyle = '#000';
            mazeCtx.lineWidth = 1;

            for (let y = 0; y < mazeHeight; y++) {
                for (let x = 0; x < mazeWidth; x++) {
                    const cell = mazeGrid[y][x];
                    const leftX = x * cellWidth;
                    const topY = y * cellHeight;

                    // Top wall
                    if (cell.walls.top) {
                        mazeCtx.beginPath();
                        mazeCtx.moveTo(leftX, topY);
                        mazeCtx.lineTo(leftX + cellWidth, topY);
                        mazeCtx.stroke();
                    }

                    // Right wall
                    if (cell.walls.right) {
                        mazeCtx.beginPath();
                        mazeCtx.moveTo(leftX + cellWidth, topY);
                        mazeCtx.lineTo(leftX + cellWidth, topY + cellHeight);
                        mazeCtx.stroke();
                    }

                    // Bottom wall
                    if (cell.walls.bottom) {
                        mazeCtx.beginPath();
                        mazeCtx.moveTo(leftX, topY + cellHeight);
                        mazeCtx.lineTo(leftX + cellWidth, topY + cellHeight);
                        mazeCtx.stroke();
                    }

                    // Left wall
                    if (cell.walls.left) {
                        mazeCtx.beginPath();
                        mazeCtx.moveTo(leftX, topY);
                        mazeCtx.lineTo(leftX, topY + cellHeight);
                        mazeCtx.stroke();
                    }
                }
            }

            // Draw exit
            const exitLeft = exitX * cellWidth;
            const exitTop = exitY * cellHeight;
            mazeCtx.fillStyle = 'green';
            mazeCtx.fillRect(exitLeft + 5, exitTop + 5, cellWidth -10, cellHeight -10);

            // Draw bots
            for (const bot of bots) {
                if (!bot.completed) {
                    const x = bot.x * cellWidth;
                    const y = bot.y * cellHeight;
                    mazeCtx.fillStyle = 'red';
                    mazeCtx.beginPath();
                    mazeCtx.arc(x + cellWidth/2, y + cellHeight/2, 5, 0, Math.PI*2);
                    mazeCtx.fill();
                }
            }
        }

        let runStepCount = 0;

        function runStep() {
            if (completedCount < bots.length) {
                for (let bot of bots) {
                    if (!bot.completed) {
                        const path = bot.path;
                        const currentIndex = bot.currentIndex + 1;
                        if (currentIndex >= path.length) {
                            // Bot has reached exit
                            bot.completed = true;
                            completedCount++;
                        } else {
                            bot.x = path[currentIndex].x;
                            bot.y = path[currentIndex].y;
                            bot.currentIndex = currentIndex;
                        }
                    }
                }
                elapsedMs += 1; // each step adds 1ms to virtual time
            }
        }

        function updateHUD() {
            document.getElementById('completed').textContent = `Completed: ${completedCount}`;
            document.getElementById('timer').textContent = `Time: ${elapsedMs}ms`;
        }

        let mazeGrid;
        let mazeWidth, mazeHeight;
        let exitX, exitY;
        let bots = [];
        let completedCount = 0;
        let elapsedMs = 0;

        function initGame() {
            // Generate new maze
            const width = 20;
            const height = 20;
            mazeGrid = generateMaze(width, height);
            mazeWidth = width;
            mazeHeight = height;

            exitX = width - 1;
            exitY = height - 1;

            // Generate bots
            bots = [];
            for (let i = 0; i < 24; i++) {
                const path = aStar(mazeGrid, [0, 0], { x: exitX, y: exitY }, i);
                if (!path.length) continue; // shouldn't happen

                bots.push({
                    x: 0,
                    y: 0,
                    path: path,
                    currentIndex: 0,
                    completed: false
                });
            }

            completedCount = 0;
            elapsedMs = 0;

            drawMaze();
            updateHUD();

            // Start animation loop
            if (animationId) cancelAnimationFrame(animationId);
            animationId = requestAnimationFrame(animate);
        }

        let animationId = null;

        function animate() {
            runStep();
            drawMaze();
            updateHUD();
            if (completedCount < bots.length) {
                animationId = requestAnimationFrame(animate);
            } else {
                cancelAnimationFrame(animationId);
            }
        }

        // Initialize game on load
        initGame();

        document.getElementById('reset').addEventListener('click', () => {
            window.game.reset();
        });

        window.game = {
            get bots() {
                return bots.map(bot => ({ x: bot.x, y: bot.y }));
            },
            get completed() {
                return completedCount;
            },
            get elapsedMs() {
                return elapsedMs;
            },
            tick(n) {
                for (let i = 0; i < n; i++) {
                    if (completedCount >= bots.length) break;
                    runStep();
                }
            },
            reset() {
                initGame();
            }
        };
    </script>
</body>
