<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8" />
    <title>Maze Game</title>
    <style>
        body {
            font-family: sans-serif;
            text-align: center;
            margin-top: 20px;
        }
        canvas {
            border: 1px solid #333;
            image-rendering: pixelated;
        }
        #hud {
            margin-top: 15px;
        }
        button {
            padding: 8px 16px;
            font-size: 14px;
            cursor: pointer;
        }
    </style>
</head>
<body>
    <canvas id="maze" width="400" height="400"></canvas>
    <div id="hud">
        Completed: <span id="completed">0</span><br/>
        Time: <span id="timer">0.0s</span><br/>
        <button id="reset">Reset</button>
    </div>

    <script>
        const MAZE_WIDTH = 17;
        const MAZE_HEIGHT = 17;
        const STEP_DURATION_MS = 100;

        const canvas = document.getElementById('maze');
        const ctx = canvas.getContext('2d');

        const completedEl = document.getElementById('completed');
        const timerEl = document.getElementById('timer');
        const resetBtn = document.getElementById('reset');

        let mazeData, path;
        let bots = [];
        let stepsElapsed = 0;
        let completedCount = 0;

        function generateMaze(width, height) {
            const visited = Array.from({ length: height }, () => Array(width).fill(false));
            const connections = Array.from({ length: height }, () => Array(width).fill(0));

            let currentX = 0, currentY = 0;
            visited[currentY][currentX] = true;
            const stack = [{ x: currentX, y: currentY }];

            while (stack.length > 0) {
                const directions = [];
                if (currentX > 0 && !visited[currentY][currentX - 1]) directions.push('left');
                if (currentX < width - 1 && !visited[currentY][currentX + 1]) directions.push('right');
                if (currentY > 0 && !visited[currentY - 1][currentX]) directions.push('up');
                if (currentY < height - 1 && !visited[currentY + 1][currentX]) directions.push('down');

                if (!directions.length) {
                    stack.pop();
                    const prev = stack[stack.length - 1] || { x: 0, y: 0 };
                    currentX = prev.x;
                    currentY = prev.y;
                    continue;
                }

                const dir = directions[Math.floor(Math.random() * directions.length)];
                let nextX = currentX, nextY = currentY;

                if (dir === 'left') nextX--;
                else if (dir === 'right') nextX++;
                else if (dir === 'up') nextY--;
                else if (dir === 'down') nextY++;

                visited[nextY][nextX] = true;
                stack.push({ x: nextX, y: nextY });
                currentX = nextX;
                currentY = nextY;

                // Mark connections
                if (dir === 'left') {
                    connections[currentY][currentX].right = 1;
                    connections[nextY][nextX].left = 1;
                } else if (dir === 'right') {
                    connections[currentY][currentX].left = 1;
                    connections[nextY][nextX].right = 1;
                } else if (dir === 'up') {
                    connections[currentY][currentX].down = 1;
                    connections[nextY][nextX].up = 1;
                } else if (dir === 'down') {
                    connections[currentY][currentX].up = 1;
                    connections[nextY][nextX].down = 1;
                }
            }

            const maze = Array.from({ length: height }, (_, y) =>
                Array.from({ length: width }, (_, x) => ({
                    top: true,
                    right: true,
                    bottom: true,
                    left: true
                }))
            );

            for (let y = 0; y < height; y++) {
                for (let x = 0; x < width; x++) {
                    if (y > 0 && connections[y][x].up) maze[y][x].top = false;
                    if (x < width - 1 && connections[y][x].right) maze[y][x].right = false;
                    if (y < height - 1 && connections[y][x].down) maze[y][x].bottom = false;
                    if (x > 0 && connections[y][x].left) maze[y][x].left = false;
                }
            }

            return {
                maze,
                start: { x: 0, y: 0 },
                exit: { x: width - 1, y: height - 1 }
            };
        }

        function bfs(mazeData) {
            const { maze, start, exit } = mazeData;
            const width = MAZE_WIDTH;
            const height = MAZE_HEIGHT;

            const queue = [start];
            const visited = new Set();
            const prev = new Map();

            function posKey(x, y) { return `${x},${y}`; }

            while (queue.length > 0) {
                const current = queue.shift();
                if (posKey(current.x, current.y) === posKey(exit.x, exit.y)) break;
                visited.add(posKey(current.x, current.y));

                const directions = [
                    { dx: 0, dy: -1 }, // up
                    { dx: 1, dy: 0 },  // right
                    { dx: 0, dy: 1 },  // down
                    { dx: -1, dy: 0 }  // left
                ];

                for (const dir of directions) {
                    const nx = current.x + dir.dx;
                    const ny = current.y + dir.dy;

                    if (nx >= 0 && nx < width && ny >= 0 && ny < height &&
                        !visited.has(posKey(nx, ny))) {

                        let canMove = false;
                        if (dir.dx === 1) {
                            canMove = !maze[current.y][current.x].right; // right wall open
                        } else if (dir.dx === -1) {
                            canMove = !maze[current.y][current.x].left; // left wall open
                        } else if (dir.dy === 1) {
                            canMove = !maze[current.y][current.x].bottom; // bottom wall open
                        } else if (dir.dy === -1) {
                            canMove = !maze[current.y][current.x].top; // top wall open
                        }

                        if (canMove) {
                            queue.push({ x: nx, y: ny });
                            prev.set(posKey(nx, ny), current);
                        }
                    }
                }
            }

            const path = [];
            let at = exit;
            while (at) {
                path.unshift({...at});
                at = prev.get(posKey(at.x, at.y));
            }

            return path.length > 0 ? path : null;
        }

        function drawMaze() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            const cellSize = canvas.width / MAZE_WIDTH;

            for (let y = 0; y < MAZE_HEIGHT; y++) {
                for (let x = 0; x < MAZE_WIDTH; x++) {
                    const { top, right, bottom, left } = mazeData.maze[y][x];
                    const px = x * cellSize;
                    const py = y * cellSize;

                    if (top) ctx.strokeRect(px, py, cellSize, 1);
                    if (right) ctx.strokeRect(px + cellSize - 1, py, 1, cellSize);
                    if (bottom) ctx.strokeRect(px, py + cellSize - 1, cellSize, 1);
                    if (left) ctx.strokeRect(px, py, 1, cellSize);
                }
            }

            const { start, exit } = mazeData;
            const cellSize = canvas.width / MAZE_WIDTH;

            // Draw start and exit
            ctx.fillStyle = 'red';
            ctx.fillRect(start.x * cellSize + 2, start.y * cellSize + 2, cellSize - 4, cellSize - 4);
            ctx.fillStyle = 'green';
            ctx.fillRect(exit.x * cellSize + 2, exit.y * cellSize + 2, cellSize - 4, cellSize - 4);
        }

        function drawBots() {
            const cellSize = canvas.width / MAZE_WIDTH;
            for (const bot of bots) {
                let progress = stepsElapsed - bot.delay;
                if (progress < 0) continue;

                const targetIndex = Math.min(progress, path.length - 1);
                const pos = path[targetIndex];
                const x = pos.x * cellSize + cellSize / 2;
                const y = pos.y * cellSize + cellSize / 2;

                ctx.fillStyle = 'blue';
                ctx.beginPath();
                ctx.arc(x, y, 3, 0, Math.PI * 2);
                ctx.fill();
            }
        }

        function updateHUD() {
            completedEl.textContent = completedCount;
            const elapsedSeconds = (stepsElapsed * STEP_DURATION_MS) / 1000;
            timerEl.textContent = `${elapsedSeconds.toFixed(1)}s`;
        }

        function resetGame() {
            mazeData = generateMaze(MAZE_WIDTH, MAZE_HEIGHT);
            path = bfs(mazeData);

            bots = [];
            for (let i = 0; i < 24; i++) {
                bots.push({
                    delay: i,
                    x: 0,
                    y: 0,
                    completed: false
                });
            }

            stepsElapsed = 0;
            completedCount = 0;

            drawMaze();
        }

        function updateBots() {
            for (const bot of bots) {
                if (!bot.completed) {
                    let progress = stepsElapsed - bot.delay;
                    const targetIndex = Math.min(progress, path.length - 1);
                    const pos = path[targetIndex];
                    bot.x = pos.x;
                    bot.y = pos.y;

                    if (targetIndex === path.length - 1 && !bot.completed) {
                        completedCount++;
                        bot.completed = true;
                    }
                }
            }
        }

        resetBtn.addEventListener('click', () => {
            resetGame();
        });

        function animate() {
            updateBots();
            drawMaze();
            drawBots();
            updateHUD();
            requestAnimationFrame(animate);
        }

        window.game = {
            bots: [],
            get completed() { return completedCount; },
            get elapsedMs() { return stepsElapsed * STEP_DURATION_MS; },
            tick(n) {
                const prevSteps = stepsElapsed;
                stepsElapsed += n;

                for (const bot of bots) {
                    if (!bot.completed && !bot._completedDuringTick) {
                        let progress = stepsElapsed - bot.delay;
                        const targetIndex = Math.min(progress, path.length - 1);
                        if (targetIndex === path.length - 1) {
                            completedCount++;
                            bot.completed = true;
                            bot._completedDuringTick = true;
                        }
                    }
                }

                // Clean up flag
                for (const bot of bots) {
                    if (bot._completedDuringTick) delete bot._completedDuringTick;
                }
            },
            reset() {
                resetGame();
            }
        };

        window.onload = () => {
            resetGame();
            animate();
        };
    </script>
</body>
</html>
